defmodule MyAppWeb.ProxyController do
  use MyAppWeb, :controller

  alias HTTPoison

  def fetch(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, %HTTPoison.Response{status_code: status_code, headers: headers, body: body}} ->
        # Pass through original headers, excluding Transfer-Encoding and Connection
        # to avoid issues with Cowboy and content length.
        passthrough_headers =
          headers
          |> Enum.reject(fn {name, _value} ->
            String.downcase(name) in ["transfer-encoding", "connection", "content-encoding"]
          end)
          |> Enum.reduce(conn, fn {name, value}, acc ->
            Plug.Conn.put_resp_header(acc, name, value)
          end)

        passthrough_headers
        |> Plug.Conn.put_status(status_code)
        |> Plug.Conn.send_resp(status_code, body)

      {:error, %HTTPoison.Error{reason: reason}} ->
        conn
        |> put_status(:bad_gateway)
        |> json(%{error: "Failed to fetch URL", reason: inspect(reason)})
    end
  end

  def fetch(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{error: "Missing 'url' parameter. Please provide a URL in the 'url' query parameter."})
  end
end